body.script:
var PM_PLAYERS    = ;
var PM_STATS      = ;
var PM_TEAMS      = ;
var PM_TOGGLE_URL = '';
var PM_PROOF_BASE = '';
var PM_UPLOAD_URL = '';
var PM_UNLINK_URL = '';

//
(function () {
  'use strict';

  var PLAYERS = PM_PLAYERS || [];
  var TEAMS   = PM_TEAMS   || [];

  /* ── State ── */
  var S = {
    stateFilter: 'all',
    payFilter:   'all',
    teamFilter:  '',
    groupBy:     'none',
    sortField:   'sl_no',
    sortDir:     'asc',
    search:      '',
  };

  /* ── DOM refs ── */
  var tbody    = document.getElementById('pm-tbody');
  var cardsEl  = document.getElementById('pm-cards');
  var emptyEl  = document.getElementById('pm-empty');
  var countEl  = document.getElementById('pm-count');
  var toastEl  = document.getElementById('pm-toast');
  var totalEl  = document.getElementById('pm-total');
  var paidNEl  = document.getElementById('pm-paid-n');
  var unpaidNEl= document.getElementById('pm-unpaid-n');
  var barEl    = document.getElementById('pm-bar');
  var toastTmr = null;

  /* ── HTML escape via DOM ── */
  function esc(s) {
    var d = document.createElement('div');
    d.textContent = String(s || '');
    return d.innerHTML;
  }

  function dash(v) {
    return v ? esc(v) : '<span style="color:#94a3b8">\u2014</span>';
  }

  /* ── State badge ── */
  function badge(st) {
    var labels = {draft: 'Draft', auction: 'In Auction', sold: 'Sold', unsold: 'Unsold'};
    return '<span class="pm-badge pm-badge-' + st + '">' + (labels[st] || st) + '</span>';
  }

  /* ── Toast ── */
  function showToast(msg, cls) {
    if (toastTmr) clearTimeout(toastTmr);
    toastEl.textContent = msg;
    toastEl.className = 'pm-toast ' + (cls || 'pm-toast-inf') + ' show';
    toastTmr = setTimeout(function () { toastEl.classList.remove('show'); }, 2600);
  }

  /* ── Stats ── */
  function renderStats() {
    var total = PLAYERS.length;
    var paid  = 0;
    var byState = {
      draft:   {t: 0, p: 0},
      auction: {t: 0, p: 0},
      sold:    {t: 0, p: 0},
      unsold:  {t: 0, p: 0},
    };
    PLAYERS.forEach(function (p) {
      if (p.amount_paid) paid++;
      if (byState[p.state]) {
        byState[p.state].t++;
        if (p.amount_paid) byState[p.state].p++;
      }
    });
    totalEl.textContent   = total;
    paidNEl.textContent   = paid;
    unpaidNEl.textContent = total - paid;
    barEl.style.width     = (total > 0 ? Math.round(paid / total * 100) : 0) + '%';

    var icons  = {draft: '\u26AB', auction: '\uD83D\uDFE1', sold: '\uD83D\uDFE2', unsold: '\uD83D\uDD34'};
    var slabls = {draft: 'Draft', auction: 'Auction', sold: 'Sold', unsold: 'Unsold'};
    Object.keys(byState).forEach(function (st) {
      var el = document.getElementById('ss-' + st);
      if (el) el.textContent = icons[st] + ' ' + slabls[st] + ' ' + byState[st].p + '/' + byState[st].t;
    });
  }

  /* ── Filter + Sort ── */
  function getFiltered() {
    var r = PLAYERS.slice();
    if (S.stateFilter !== 'all') {
      r = r.filter(function (p) { return p.state === S.stateFilter; });
    }
    if (S.payFilter === 'paid')   r = r.filter(function (p) { return p.amount_paid; });
    if (S.payFilter === 'unpaid') r = r.filter(function (p) { return !p.amount_paid; });
    if (S.teamFilter) {
      r = r.filter(function (p) { return p.team === S.teamFilter; });
    }
    if (S.search) {
      var q = S.search.toLowerCase();
      r = r.filter(function (p) {
        return (p.name    || '').toLowerCase().indexOf(q) !== -1 ||
               (p.contact || '').toLowerCase().indexOf(q) !== -1 ||
               (p.team    || '').toLowerCase().indexOf(q) !== -1 ||
               (p.manager || '').toLowerCase().indexOf(q) !== -1 ||
               (p.tier    || '').toLowerCase().indexOf(q) !== -1 ||
               String(p.sl_no || '').indexOf(q) !== -1;
      });
    }
    var sf = S.sortField;
    var sd = S.sortDir === 'asc' ? 1 : -1;
    r.sort(function (a, b) {
      var av = a[sf], bv = b[sf];
      if (av == null) av = typeof bv === 'number' ? -Infinity : '';
      if (bv == null) bv = typeof av === 'number' ? -Infinity : '';
      if (typeof av === 'boolean') av = av ? 1 : 0;
      if (typeof bv === 'boolean') bv = bv ? 1 : 0;
      if (typeof av === 'string')  av = av.toLowerCase();
      if (typeof bv === 'string')  bv = bv.toLowerCase();
      if (av < bv) return -1 * sd;
      if (av > bv) return  1 * sd;
      return 0;
    });
    return r;
  }

  /* ── Row builder (table) ── */
  function mkRow(p, idx) {
    var chk = p.amount_paid ? ' checked' : '';
    var paid = p.amount_paid ? '1' : '0';
    return '<tr>' +
      '<td>' + (p.sl_no || idx + 1) + '</td>' +
      '<td><div class="pm-player-cell">' +
        '<img class="pm-thumb" ' +
             'src="/web/image/auction.team.player/' + p.id + '/photo" ' +
             'onerror="this.onerror=null;this.src=\'/auction_module/static/img/default_icon.png\'" ' +
             'loading="lazy" alt="">' +
        '<div><div class="pm-pname">' + esc(p.name) + '</div>' +
        (p.role ? '<div class="pm-prole">' + esc(p.role) + '</div>' : '') +
        '</div></div></td>' +
      '<td>' + dash(p.contact) + '</td>' +
      '<td>' +
        '<button class="pm-pay-btn ' + (p.amount_paid ? 'is-paid' : 'is-unpaid') + '" ' +
                'data-pay-id="' + p.id + '" data-paid="' + paid + '">' +
          (p.amount_paid ? '&#10003; Paid' : '&#10007; Unpaid') +
        '</button>' +
      '</td>' +
      '<td>' + dash(p.team) + '</td>' +
      '<td>' + dash(p.manager) + '</td>' +
      '<td>' + badge(p.state) + '</td>' +
      '<td style="text-align:center;white-space:nowrap">' +
        (p.proof_att_id ? '<button class="pm-proof-btn" data-id="' + p.id + '" data-name="' + esc(p.name) + '" title="View payment proof" style="margin-right:3px">&#129534;</button>' : '') +
        (p.proof_att_id ? '<button class="pm-unlink-btn" data-unlink-id="' + p.id + '" title="Remove payment proof" style="margin-right:3px">&#128465;</button>' : '') +
        '<button class="pm-upload-btn" data-upload-id="' + p.id + '" title="Upload payment screenshot">&#128228;</button>' +
      '</td>' +
      '</tr>';
  }

  /* ── Card builder (mobile) ── */
  function mkCard(p, idx) {
    var chk  = p.amount_paid ? ' checked' : '';
    var paid = p.amount_paid ? '1' : '0';
    return '<div class="pm-card pm-card-' + p.state + '">' +
      '<div class="pm-card-head">' +
        '<img class="pm-card-photo" ' +
             'src="/web/image/auction.team.player/' + p.id + '/photo" ' +
             'onerror="this.onerror=null;this.src=\'/auction_module/static/img/default_icon.png\'" ' +
             'loading="lazy" alt="">' +
        '<div class="pm-card-info">' +
          '<div class="pm-card-name">' + esc(p.name) + '</div>' +
          '<div class="pm-card-meta">' + badge(p.state) +
            (p.role ? '<span style="font-size:.6rem;color:#64748b">' + esc(p.role) + '</span>' : '') +
          '</div>' +
        '</div>' +
        '<span class="pm-card-sl">#' + (p.sl_no || idx + 1) + '</span>' +
      '</div>' +
      '<div class="pm-card-body">' +
        '<div class="pm-card-field"><div class="pm-fl">Contact</div><div class="pm-fv">' + dash(p.contact) + '</div></div>' +
        '<div class="pm-card-field"><div class="pm-fl">Team</div><div class="pm-fv">' + dash(p.team) + '</div></div>' +
        '<div class="pm-card-field"><div class="pm-fl">Manager</div><div class="pm-fv">' + dash(p.manager) + '</div></div>' +
        '<div class="pm-card-field"><div class="pm-fl">Tier</div><div class="pm-fv">' + dash(p.tier) + '</div></div>' +
      '</div>' +
      '<div class="pm-card-pay">' +
        '<span class="pm-card-pay-lbl">Payment Status</span>' +
        '<div style="display:flex;align-items:center;gap:8px;">' +
          (p.proof_att_id
            ? '<button class="pm-proof-btn" data-id="' + p.id + '" data-name="' + esc(p.name) + '" title="View payment proof" style="margin-right:3px">&#129534;</button>'
            : '') +
          (p.proof_att_id
            ? '<button class="pm-unlink-btn" data-unlink-id="' + p.id + '" title="Remove payment proof" style="margin-right:3px">&#128465;</button>'
            : '') +
          '<button class="pm-upload-btn" data-upload-id="' + p.id + '" title="Upload payment screenshot">&#128228;</button>' +
          '<button class="pm-pay-btn ' + (p.amount_paid ? 'is-paid' : 'is-unpaid') + '" ' +
                  'data-pay-id="' + p.id + '" data-paid="' + paid + '">' +
            (p.amount_paid ? '&#10003; Paid' : '&#10007; Unpaid') +
          '</button>' +
        '</div>' +
      '</div>' +
    '</div>';
  }

  /* ── Group helper ── */
  function groupData(data) {
    var groups = {}, order = [];
    var stateLabels = {draft: 'Draft', auction: 'In Auction', sold: 'Sold', unsold: 'Unsold'};
    data.forEach(function (p) {
      var key;
      if      (S.groupBy === 'state')   key = p.state;
      else if (S.groupBy === 'team')    key = p.team    || '(No Team)';
      else if (S.groupBy === 'payment') key = p.amount_paid ? 'Paid' : 'Unpaid';
      else if (S.groupBy === 'tier')    key = p.tier    || '(No Tier)';
      else key = '__all__';
      if (!groups[key]) { groups[key] = []; order.push(key); }
      groups[key].push(p);
    });
    return order.map(function (k) {
      var label = S.groupBy === 'state' ? (stateLabels[k] || k) : k;
      return {key: k, label: label, players: groups[k]};
    });
  }

  /* ── Render ── */
  function render() {
    var data = getFiltered();
    countEl.textContent = data.length + ' player' + (data.length === 1 ? '' : 's');
    emptyEl.style.display = data.length === 0 ? '' : 'none';

    var tbHtml = '', carHtml = '';

    if (S.groupBy === 'none') {
      data.forEach(function (p, i) {
        tbHtml  += mkRow(p, i);
        carHtml += mkCard(p, i);
      });
    } else {
      groupData(data).forEach(function (g) {
        tbHtml  += '<tr class="pm-group-row"><td colspan="8">' +
                   '<span class="pm-group-row-label">' + esc(g.label) + '</span>' +
                   '<span class="pm-group-row-count">' + g.players.length + ' players</span>' +
                   '</td></tr>';
        carHtml += '<div class="pm-gh"><span>' + esc(g.label) + '</span>' +
                   '<span class="pm-gh-count">' + g.players.length + ' players</span></div>';
        g.players.forEach(function (p, i) {
          tbHtml  += mkRow(p, i);
          carHtml += mkCard(p, i);
        });
      });
    }

    tbody.innerHTML  = tbHtml;
    cardsEl.innerHTML = carHtml;
    attachToggles();
  }

  /* ── Toggle payment (delegated, attached once) ── */
  function attachToggles() { /* no-op — handled by delegated listener below */ }

  document.addEventListener('click', function (e) {
    var btn = e.target.closest('button.pm-pay-btn[data-pay-id]');
    if (!btn) return;
    var pid  = parseInt(btn.getAttribute('data-pay-id'), 10);
    var prev = btn.getAttribute('data-paid') === '1';
    var next = !prev;

    /* optimistic UI update */
    btn.classList.add('pm-pay-saving');

    fetch(PM_TOGGLE_URL, {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({
        jsonrpc: '2.0', id: 1, method: 'call',
        params: {player_id: pid, paid: next},
      }),
    })
    .then(function (r) { return r.json(); })
    .then(function (d) {
      if (d.result && d.result.success) {
        /* update master array then re-render */
        for (var i = 0; i < PLAYERS.length; i++) {
          if (PLAYERS[i].id === pid) { PLAYERS[i].amount_paid = next; break; }
        }
        render();
        showToast(next ? '\u2705 Marked as Paid' : '\u274C Marked as Unpaid',
                  next ? 'ok' : 'err');
      } else {
        btn.classList.remove('pm-pay-saving');
        showToast('\u26A0\uFE0F Could not save. Try again.', 'err');
      }
    })
    .catch(function () {
      btn.classList.remove('pm-pay-saving');
      showToast('\u26A0\uFE0F Network error.', 'err');
    });
  });

  /* ── Sort UI sync ── */
  function syncSortUI() {
    document.querySelectorAll('.pm-table th.sortable').forEach(function (th) {
      var si = th.querySelector('.si');
      if (th.getAttribute('data-sort') === S.sortField) {
        th.classList.add('sorted');
        if (si) si.textContent = S.sortDir === 'asc' ? '\u2191' : '\u2193';
      } else {
        th.classList.remove('sorted');
        if (si) si.textContent = '\u2195';
      }
    });
    var sd = document.getElementById('pm-sort-by');
    if (sd) sd.value = S.sortField;
    var db = document.getElementById('pm-dir-btn');
    if (db) db.textContent = S.sortDir === 'asc' ? '\u2191' : '\u2193';
  }

  /* ── Upload proof ── */
  var uploadingPid = null;
  var proofFileInput = document.getElementById('pm-proof-file');

  document.addEventListener('click', function (e) {
    var btn = e.target.closest('button.pm-upload-btn[data-upload-id]');
    if (!btn) return;
    uploadingPid = parseInt(btn.getAttribute('data-upload-id'), 10);
    proofFileInput.value = '';
    proofFileInput.click();
  });

  proofFileInput.addEventListener('change', function () {
    if (!this.files || !this.files[0] || !uploadingPid) return;
    var pid  = uploadingPid;
    var file = this.files[0];

    /* Disable all upload buttons for this player while uploading */
    document.querySelectorAll('button.pm-upload-btn[data-upload-id="' + pid + '"]').forEach(function (b) {
      b.classList.add('uploading');
      b.textContent = '\u23F3';
    });
    showToast('Uploading screenshot\u2026', 'ok');

    var fd = new FormData();
    fd.append('file', file);
    fd.append('player_id', pid);

    fetch(PM_UPLOAD_URL, { method: 'POST', credentials: 'include', body: fd })
      .then(function (r) { return r.json(); })
      .then(function (d) {
        if (d.success) {
          /* Update in-memory player record */
          for (var i = 0; i < PLAYERS.length; i++) {
            if (PLAYERS[i].id === pid) {
              PLAYERS[i].proof_data    = d.proof_data;
              PLAYERS[i].proof_att_id  = 1;
              PLAYERS[i].amount_paid   = true;
              break;
            }
          }
          render();
          showToast('Screenshot uploaded \u2714 Player marked as Paid', 'ok');
        } else {
          showToast('Upload failed: ' + (d.error || 'Unknown error'), 'err');
          document.querySelectorAll('button.pm-upload-btn[data-upload-id="' + pid + '"]').forEach(function (b) {
            b.classList.remove('uploading'); b.textContent = '\uD83D\uDCE4';
          });
        }
      })
      .catch(function (err) {
        showToast('Upload error: ' + err.message, 'err');
        document.querySelectorAll('button.pm-upload-btn[data-upload-id="' + pid + '"]').forEach(function (b) {
          b.classList.remove('uploading'); b.textContent = '\uD83D\uDCE4';
        });
      });
  });

  /* ── Unlink proof ── */
  document.addEventListener('click', function (e) {
    var btn = e.target.closest('button.pm-unlink-btn[data-unlink-id]');
    if (!btn) return;
    var pid = parseInt(btn.getAttribute('data-unlink-id'), 10);
    var p   = PLAYERS.find(function (x) { return x.id === pid; });
    var name = p ? p.name : 'this player';
    if (!confirm('Remove payment proof for ' + name + '?')) return;

    var fd = new FormData();
    fd.append('player_id', pid);
    fetch(PM_UNLINK_URL, { method: 'POST', credentials: 'include', body: fd })
      .then(function (r) { return r.json(); })
      .then(function (d) {
        if (d.success) {
          for (var i = 0; i < PLAYERS.length; i++) {
            if (PLAYERS[i].id === pid) {
              PLAYERS[i].proof_att_id = 0;
              PLAYERS[i].proof_data   = '';
              break;
            }
          }
          render();
          showToast('Payment proof removed', 'ok');
        } else {
          showToast('Failed to remove: ' + (d.error || 'Unknown error'), 'err');
        }
      })
      .catch(function (err) {
        showToast('Error: ' + err.message, 'err');
      });
  });

  /* ── Init ── */
  function init() {
    initTheme();
    renderStats();
    initTeamChips();

    /* ── Theme toggle ── */
    var themeBtn = document.getElementById('pm-theme-btn');
    if (themeBtn) {
      themeBtn.addEventListener('click', function () {
        var cur = document.documentElement.getAttribute('data-theme') === 'dark' ? 'dark' : 'light';
        var next = cur === 'dark' ? 'light' : 'dark';
        applyTheme(next);
        localStorage.setItem('pm-theme', next);
      });
    }

    /* ── Refresh button ── */
    var refreshBtn = document.getElementById('pm-refresh-btn');
    if (refreshBtn) {
      refreshBtn.addEventListener('click', function () {
        refreshBtn.style.opacity = '.4';
        refreshBtn.style.pointerEvents = 'none';
        location.reload();
      });
    }

    /* ── Export dropdown toggle ── */
    var exportWrap = document.getElementById('pm-export-wrap');
    var exportBtn  = document.getElementById('pm-export-btn');
    if (exportBtn && exportWrap) {
      exportBtn.addEventListener('click', function (e) {
        e.stopPropagation();
        exportWrap.classList.toggle('open');
      });
      document.addEventListener('click', function () { exportWrap.classList.remove('open'); });
    }

    var csvBtn = document.getElementById('pm-export-csv');
    if (csvBtn) csvBtn.addEventListener('click', function () { exportExcel(); exportWrap.classList.remove('open'); });

    var pdfBtn = document.getElementById('pm-export-pdf');
    if (pdfBtn) pdfBtn.addEventListener('click', function () { exportPDF(); exportWrap.classList.remove('open'); });

    /* Search */
    document.getElementById('pm-search').addEventListener('input', function () {
      S.search = this.value.trim();
      render();
    });

    /* State tabs */
    document.querySelectorAll('.pm-tab').forEach(function (btn) {
      btn.addEventListener('click', function () {
        document.querySelectorAll('.pm-tab').forEach(function (b) { b.classList.remove('active'); });
        btn.classList.add('active');
        S.stateFilter = btn.getAttribute('data-state');
        render();
      });
    });

    /* Payment filter */
    document.getElementById('pm-pay-filter').addEventListener('change', function () {
      S.payFilter = this.value;
      render();
    });

    /* Group by */
    document.getElementById('pm-group-by').addEventListener('change', function () {
      S.groupBy = this.value;
      render();
    });

    /* Sort by dropdown */
    document.getElementById('pm-sort-by').addEventListener('change', function () {
      S.sortField = this.value;
      S.sortDir = 'asc';
      syncSortUI();
      render();
    });

    /* Sort direction */
    document.getElementById('pm-dir-btn').addEventListener('click', function () {
      S.sortDir = S.sortDir === 'asc' ? 'desc' : 'asc';
      syncSortUI();
      render();
    });

    /* Column header click to sort */
    document.querySelectorAll('.pm-table th.sortable').forEach(function (th) {
      th.addEventListener('click', function () {
        var f = th.getAttribute('data-sort');
        if (S.sortField === f) {
          S.sortDir = S.sortDir === 'asc' ? 'desc' : 'asc';
        } else {
          S.sortField = f;
          S.sortDir = 'asc';
        }
        syncSortUI();
        render();
      });
    });

    syncSortUI();
    render();
  }

  /* ── Team quick-filter chips ── */
  function initTeamChips() {
    var wrap = document.getElementById('pm-team-chips-wrap');
    var container = document.getElementById('pm-team-chips');
    if (!wrap || !container || !TEAMS.length) return;

    wrap.classList.add('has-teams');

    /* "All Teams" chip */
    var allChip = document.createElement('button');
    allChip.className = 'pm-team-chip pm-team-chip-all active';
    allChip.textContent = 'All Teams';
    allChip.setAttribute('data-team', '');
    container.appendChild(allChip);

    /* One chip per team */
    TEAMS.forEach(function (t) {
      var chip = document.createElement('button');
      chip.className = 'pm-team-chip';
      chip.setAttribute('data-team', t.name);

      /* Logo or initials fallback */
      if (t.has_logo) {
        var img = document.createElement('img');
        img.className = 'pm-team-chip-logo';
        img.src = '/web/image/auction.team/' + t.id + '/logo';
        img.alt = '';
        img.onerror = function () {
          /* swap to initials on load error */
          var fb = document.createElement('span');
          fb.className = 'pm-team-chip-logo-fb';
          fb.textContent = (t.name || '?').slice(0, 2);
          chip.replaceChild(fb, img);
        };
        chip.appendChild(img);
      } else {
        var fb = document.createElement('span');
        fb.className = 'pm-team-chip-logo-fb';
        fb.textContent = (t.name || '?').slice(0, 2);
        chip.appendChild(fb);
      }

      var lbl = document.createElement('span');
      lbl.textContent = t.name;
      chip.appendChild(lbl);
      container.appendChild(chip);
    });

    /* Click handler */
    container.addEventListener('click', function (e) {
      var chip = e.target.closest('.pm-team-chip');
      if (!chip) return;
      container.querySelectorAll('.pm-team-chip').forEach(function (c) { c.classList.remove('active'); });
      chip.classList.add('active');
      S.teamFilter = chip.getAttribute('data-team');
      render();
    });
  }

  /* ── Theme ── */
  function applyTheme(theme) {
    document.documentElement.setAttribute('data-theme', theme);
    var btn = document.getElementById('pm-theme-btn');
    if (btn) btn.innerHTML = theme === 'dark' ? '&#9790;&#65039;' : '&#9728;&#65039;';
  }

  function initTheme() {
    var saved = (typeof localStorage !== 'undefined' && localStorage.getItem('pm-theme')) || 'light';
    applyTheme(saved);
  }

  /* ── XML escape for SpreadsheetML ── */
  function escXml(s) {
    return String(s || '')
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  /* ── Filter label for exports ── */
  function buildFilterLabel() {
    var parts = [];
    var stateMap = {all: 'All States', draft: 'Draft', auction: 'In Auction', sold: 'Sold', unsold: 'Unsold'};
    parts.push('State: ' + (stateMap[S.stateFilter] || S.stateFilter));
    if (S.teamFilter) parts.push('Team: ' + S.teamFilter);
    if (S.payFilter !== 'all') parts.push('Payment: ' + (S.payFilter === 'paid' ? 'Paid' : 'Unpaid'));
    if (S.search) parts.push('Search: "' + S.search + '"');
    if (S.groupBy !== 'none') parts.push('Grouped by: ' + S.groupBy);
    parts.push('Sort: ' + S.sortField + ' ' + (S.sortDir === 'asc' ? 'ASC' : 'DESC'));
    return parts.join(' | ');
  }

  /* ── Excel Export (SpreadsheetML .xls with colour-coded rows) ── */
  function exportExcel() {
    var rows = getFiltered();
    var ts = new Date().toISOString().slice(0, 10);
    var navSub = document.querySelector('.pm-nav-sub');
    var tournName = navSub ? navSub.textContent : 'Tournament';

    var x = '';
    x += '<?xml version="1.0" encoding="UTF-8"?>\r\n';
    x += '<?mso-application progid="Excel.Sheet"?>\r\n';
    x += '<Workbook xmlns="urn:schemas-microsoft-com:office:spreadsheet"';
    x += ' xmlns:ss="urn:schemas-microsoft-com:office:spreadsheet"';
    x += ' xmlns:x="urn:schemas-microsoft-com:office:excel">\r\n';
    x += '<DocumentProperties xmlns="urn:schemas-microsoft-com:office:office">';
    x += '<Title>Players Payment Status Tracker</Title>';
    x += '<Author>Auction Module</Author>';
    x += '</DocumentProperties>\r\n';
    x += '<Styles>\r\n';
    x += '<Style ss:ID="hdr"><Alignment ss:Horizontal="Center"/><Font ss:Bold="1" ss:Color="#FFFFFF" ss:Size="11"/><Interior ss:Color="#1A2744" ss:Pattern="Solid"/><Borders><Border ss:Position="Bottom" ss:LineStyle="Continuous" ss:Weight="1" ss:Color="#F4C20D"/></Borders></Style>\r\n';
    x += '<Style ss:ID="ttl"><Font ss:Bold="1" ss:Size="14" ss:Color="#1A2744"/></Style>\r\n';
    x += '<Style ss:ID="meta"><Font ss:Italic="1" ss:Size="9" ss:Color="#64748B"/></Style>\r\n';
    x += '<Style ss:ID="paid"><Interior ss:Color="#DCFCE7" ss:Pattern="Solid"/></Style>\r\n';
    x += '<Style ss:ID="paid_c"><Interior ss:Color="#DCFCE7" ss:Pattern="Solid"/><Font ss:Bold="1" ss:Color="#15803D"/></Style>\r\n';
    x += '<Style ss:ID="unp"><Interior ss:Color="#FEE2E2" ss:Pattern="Solid"/></Style>\r\n';
    x += '<Style ss:ID="unp_c"><Interior ss:Color="#FEE2E2" ss:Pattern="Solid"/><Font ss:Bold="1" ss:Color="#DC2626"/></Style>\r\n';
    x += '</Styles>\r\n';
    x += '<Worksheet ss:Name="Payment Status">\r\n';
    x += '<Table ss:DefaultColumnWidth="110">\r\n';
    x += '<Column ss:Width="35"/><Column ss:Width="170"/><Column ss:Width="125"/>';
    x += '<Column ss:Width="85"/><Column ss:Width="85"/><Column ss:Width="145"/>';
    x += '<Column ss:Width="125"/><Column ss:Width="100"/>\r\n';
    /* Title rows */
    x += '<Row><Cell ss:StyleID="ttl" ss:MergeAcross="7"><Data ss:Type="String">Players Payment Status Tracker - ' + escXml(tournName) + '</Data></Cell></Row>\r\n';
    x += '<Row><Cell ss:StyleID="meta" ss:MergeAcross="7"><Data ss:Type="String">' + escXml(buildFilterLabel()) + ' | ' + rows.length + ' players</Data></Cell></Row>\r\n';
    x += '<Row><Cell ss:StyleID="meta" ss:MergeAcross="7"><Data ss:Type="String">Exported: ' + escXml(new Date().toLocaleString()) + '</Data></Cell></Row>\r\n';
    x += '<Row/>\r\n';
    /* Header row */
    var hdrs = ['#', 'Player Name', 'Contact', 'Payment', 'State', 'Team', 'Manager', 'Tier'];
    x += '<Row>';
    hdrs.forEach(function (h) { x += '<Cell ss:StyleID="hdr"><Data ss:Type="String">' + escXml(h) + '</Data></Cell>'; });
    x += '</Row>\r\n';
    /* Data rows */
    rows.forEach(function (p, i) {
      var base = p.amount_paid ? 'paid' : 'unp';
      var payCell = p.amount_paid ? 'paid_c' : 'unp_c';
      x += '<Row>';
      x += '<Cell ss:StyleID="' + base + '"><Data ss:Type="Number">' + (i + 1) + '</Data></Cell>';
      x += '<Cell ss:StyleID="' + base + '"><Data ss:Type="String">' + escXml(p.name || '') + '</Data></Cell>';
      x += '<Cell ss:StyleID="' + base + '"><Data ss:Type="String">' + escXml(p.contact || p.masked_contact || '') + '</Data></Cell>';
      x += '<Cell ss:StyleID="' + payCell + '"><Data ss:Type="String">' + (p.amount_paid ? 'Paid' : 'Unpaid') + '</Data></Cell>';
      x += '<Cell ss:StyleID="' + base + '"><Data ss:Type="String">' + escXml(p.state || '') + '</Data></Cell>';
      x += '<Cell ss:StyleID="' + base + '"><Data ss:Type="String">' + escXml(p.team || '') + '</Data></Cell>';
      x += '<Cell ss:StyleID="' + base + '"><Data ss:Type="String">' + escXml(p.manager || '') + '</Data></Cell>';
      x += '<Cell ss:StyleID="' + base + '"><Data ss:Type="String">' + escXml(p.tier || '') + '</Data></Cell>';
      x += '</Row>\r\n';
    });
    x += '</Table>\r\n</Worksheet>\r\n</Workbook>';

    var blob = new Blob([x], {type: 'application/vnd.ms-excel;charset=utf-8;'});
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url;
    a.download = 'payment_marker_' + ts + '.xls';
    document.body.appendChild(a);
    a.click();
    setTimeout(function () { document.body.removeChild(a); URL.revokeObjectURL(url); }, 600);
    showToast('Excel exported (' + rows.length + ' rows)', 'pm-toast-ok');
  }

  /* ── PDF Export (popup window → print dialog) ── */
  function exportPDF() {
    var rows = getFiltered();
    var navSub = document.querySelector('.pm-nav-sub');
    var tournName = navSub ? navSub.textContent : '';
    var filterLabel = buildFilterLabel();
    var dateStr = new Date().toLocaleString();

    var h = '';
    h += '<!DOCTYPE html><html><head><meta charset="UTF-8">';
    h += '<title>Players Payment Status Tracker - ' + tournName + '</title>';
    h += '<style>';
    h += 'body{font-family:Arial,Helvetica,sans-serif;margin:24px;color:#111;font-size:12px;}';
    h += '.hdr{border-bottom:2.5px solid #1a2744;padding-bottom:12px;margin-bottom:14px;display:flex;align-items:center;justify-content:space-between;}';
    h += '.hdr-left{display:flex;align-items:center;gap:10px;}';
    h += '.hdr-icon{height:38px;width:auto;}';
    h += '.hdr-app-name{font-size:15px;font-weight:900;color:#1a2744;line-height:1.2;}';
    h += '.hdr-app-tag{font-size:8px;color:#64748b;text-transform:uppercase;letter-spacing:1px;}';
    h += '.hdr-right{text-align:right;}';
    h += '.hdr-page-title{font-size:14px;font-weight:800;color:#1a2744;}';
    h += '.hdr-tourn{font-size:10px;color:#64748b;margin-top:2px;}';
    h += 'h1{font-size:17px;color:#1a2744;margin:0 0 4px;}';
    h += '.meta{font-size:10px;color:#64748b;margin-bottom:2px;}';
    h += 'table{width:100%;border-collapse:collapse;margin-top:14px;font-size:11px;}';
    h += 'th{background:#1a2744;color:#fff;padding:7px 8px;text-align:left;-webkit-print-color-adjust:exact;print-color-adjust:exact;}';
    h += 'td{padding:5px 8px;border-bottom:1px solid #e2e8f0;vertical-align:middle;}';
    h += 'tr.paid td{background:#dcfce7;-webkit-print-color-adjust:exact;print-color-adjust:exact;}';
    h += 'tr.unp td{background:#fee2e2;-webkit-print-color-adjust:exact;print-color-adjust:exact;}';
    h += '.p{color:#15803d;font-weight:700;}.u{color:#dc2626;font-weight:700;}';
    h += '@media print{body{margin:10px;}@page{margin:1cm;}}';
    h += '</style></head><body>';
    h += '<div class="hdr">';
    h += '  <div class="hdr-left">';
    h += '    <img class="hdr-icon" src="/auction_module/static/description/icon.png" alt="AuctionChamp"/>';
    h += '    <div><div class="hdr-app-name">AuctionChamp</div><div class="hdr-app-tag">Auction Management Platform</div></div>';
    h += '  </div>';
    h += '  <div class="hdr-right">';
    h += '    <div class="hdr-page-title">&#128203; Players Payment Status Tracker</div>';
    h += '    <div class="hdr-tourn">' + tournName + '</div>';
    h += '  </div>';
    h += '</div>';
    h += '<div class="meta">' + filterLabel + ' &nbsp;|&nbsp; ' + rows.length + ' players</div>';
    h += '<div class="meta">Generated: ' + dateStr + '</div>';
    h += '<table><thead><tr>';
    ['#','Player Name','Contact','Payment','State','Team','Manager','Tier'].forEach(function (c) {
      h += '<th>' + c + '</th>';
    });
    h += '</tr></thead><tbody>';
    rows.forEach(function (p, i) {
      var paid = p.amount_paid;
      var cls = paid ? 'paid' : 'unp';
      function ex(s) {
        return String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
      }
      h += '<tr class="' + cls + '">';
      h += '<td>' + (i + 1) + '</td>';
      h += '<td>' + ex(p.name || '') + '</td>';
      h += '<td>' + ex(p.contact || p.masked_contact || '') + '</td>';
      h += '<td><span class="' + (paid ? 'p' : 'u') + '">' + (paid ? '&#10003; Paid' : '&#10007; Unpaid') + '</span></td>';
      h += '<td>' + ex(p.state || '') + '</td>';
      h += '<td>' + ex(p.team || '') + '</td>';
      h += '<td>' + ex(p.manager || '') + '</td>';
      h += '<td>' + ex(p.tier || '') + '</td>';
      h += '</tr>';
    });
    h += '</tbody></table></body></html>';

    var pw = window.open('', '_blank', 'width=1100,height=750,menubar=yes,toolbar=yes');
    if (!pw) {
      showToast('Allow pop-ups for PDF export', 'pm-toast-err');
      return;
    }
    pw.document.open();
    pw.document.write(h);
    pw.document.close();
    pw.focus();
    setTimeout(function () { pw.print(); }, 600);
  }

  /* boot */
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }

  /* ── Payment Proof Lightbox ── */
  var lbEl    = document.getElementById('pm-lb');
  var lbTitle = document.getElementById('pm-lb-title');
  var lbWrap  = document.getElementById('pm-lb-img-wrap');

  function openProof(playerId, playerName) {
    var pid = parseInt(playerId, 10);
    var p   = null;
    for (var i = 0; i < PLAYERS.length; i++) { if (PLAYERS[i].id === pid) { p = PLAYERS[i]; break; } }

    lbTitle.textContent = '\uD83E\uDDFE ' + (playerName ? playerName + ' \u2014 ' : '') + 'Payment Proof';

    if (!p || !p.proof_data) {
      lbWrap.innerHTML = '<p style="color:var(--tx2);padding:24px;text-align:center;font-size:.95rem">No screenshot uploaded for this player.</p>';
    } else {
      lbWrap.innerHTML = '<img src="' + p.proof_data + '" style="max-width:100%;max-height:calc(90vh - 80px);object-fit:contain;border-radius:6px;display:block;margin:auto" alt="Payment proof"/>';
    }

    lbEl.classList.add('open');
  }

  function closeProof() {
    lbEl.classList.remove('open');
    lbWrap.innerHTML = '';
  }

  /* Wire lightbox close */
  document.getElementById('pm-lb-close').addEventListener('click', closeProof);
  lbEl.addEventListener('click', function (e) { if (e.target === lbEl) closeProof(); });
  document.addEventListener('keydown', function (e) { if (e.key === 'Escape') closeProof(); });

  /* Wire proof buttons (delegated — works for dynamically rendered rows/cards) */
  document.addEventListener('click', function (e) {
    var btn = e.target.closest('button.pm-proof-btn[data-id]');
    if (!btn) return;
    openProof(btn.getAttribute('data-id'), btn.getAttribute('data-name'));
  });

})();
